SELECT PSP_ARBEITSSCHRITT_NUMMER AS AS_NUMMER, tPPS_SKKALP.*  FROM ( SELECT CAST(PSP_POSITION_NUMMER AS VARCHAR(20)) AS PSP_POSITION_NUMMER, CAST(PSP_TYP_POSITION AS SMALLINT) AS PSP_TYP_POSITION, '' AS KP_INTERNTEXT, tPRP_AW.PRP_AW AS PRP_AW, tPRP_AW.PRP_AW_INDIKATOR AS PRP_AW_INDIKATOR, 0 AS KP_FLAG_AKT_PREIS_EINKAUF, CAST( PSP_PP_STATUS_PRODUKTION  AS SMALLINT) AS PSP_PP_STATUS_PRODUKTION, CAST(PSP_ZEIT_TAGE_DURCHLAUFZEIT AS FLOAT) AS PSP_ZEIT_TAGE_DURCHLAUFZEIT, CAST(PSP_ZEIT_UEBERLAPPUNG_PROZENT AS FLOAT) AS PSP_ZEIT_UEBERLAPPUNG_PROZENT, CAST(PSP_PP_STATUS_ANZAHL_TAGE_PRODUKTION AS SMALLINT) AS PSP_PP_STATUS_ANZAHL_TAGE_PRODUKTION, CAST(CASE WHEN ISDATE(PSP_PP_DATUM_START) = 1 THEN CAST((CONVERT(varchar, PSP_PP_DATUM_START, 104))as datetime) END AS datetime) AS PSP_PP_DATUM_START, CAST(PSP_PP_DATUM_START_STATUS AS SMALLINT) AS PSP_PP_DATUM_START_STATUS, CAST(tPPS_ARBSCHR.AS_NUMMER AS VARCHAR(50)) AS PSP_ARBEITSSCHRITT_NUMMER, CAST(PSP_BEZEICHNUNG AS VARCHAR(4000)) AS PSP_BEZEICHNUNG, CAST('' AS VARCHAR(4000)) AS PSP_INTERNTEXT, CAST(PSP_BEZEICHNUNG AS VARCHAR(4000)) AS PSP_BEZEICHNUNG_FORMEL, CAST(PSP_MENGE_SOLL AS FLOAT) AS PSP_MENGE_SOLL, CAST(PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL AS FLOAT) AS PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL, CAST(CAST(PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL as int) AS VARCHAR(50)) + ',' + SUBSTRING(CAST((PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL - CAST(PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL AS INT)) AS VARCHAR(50)), 3,LEN(CAST((PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL - CAST(PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL AS INT)) AS VARCHAR(50)))) AS PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL, REPLACE(CAST(PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL AS VARCHAR(50)), '.', ',') AS PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL, REPLACE(CAST(CASE WHEN PSP_TYP_ERFASSUNG_ZEIT = 0 THEN (ROUND((PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL * PSP_MENGE_SOLL), 0) + PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL) ELSE CASE WHEN PSP_TYP_ERFASSUNG_ZEIT = 1 THEN PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL + PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL END END AS VARCHAR(50)), '.', ',') AS PSP_ZEIT_MINUTEN_GESAMT_SOLL, CAST(PSP_PREIS_HK_FK_EK_GP AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP, CAST(PSP_PREIS_VK_IDEAL AS FLOAT) AS PSP_PREIS_VK_IDEAL, CAST(PSP_PREIS_VK_MINIMAL AS FLOAT) AS PSP_PREIS_VK_MINIMAL, CAST(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP AS MONEY) AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP, CAST(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP AS MONEY) AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP, CAST(CASE WHEN PSP_TYP_POSITION = 0 THEN 'Stück' ELSE '' END AS VARCHAR(10)) AS PSP_DIMENSION_BEZEICHNUNG, CAST(PSP_NEUER_FERTIGUNGSABSCHNITT AS SMALLINT) AS PSP_NEUER_FERTIGUNGSABSCHNITT, CAST(PSP_TYP_POSITION AS SMALLINT) AS D4IV_TYP_POSITION, CAST(0 AS SMALLINT) AS D4IV_TYP_HERKUNFT, CAST(PSP_IDAS AS INT) AS PSP_IDAS, CAST(0 AS SMALLINT) AS PSP_IDSKKK, CAST(PSP_TYP_SPERRE AS INT) AS D4IV_TYP_SPERRE, CAST(PSP_IDPSKKK AS INT) AS PSP_IDPSKKK, CAST(PSK_IDBEBK AS INT) AS PSKALK_IDBEBK, CAST(tPPS_SKKALP.ID AS INT) AS ID, CAST(PSK_IDBEBP AS INT) AS PSKALK_IDBEBP, CASE WHEN tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 0 THEN CAST(CASE WHEN BP_STATUS_ZEITERFASSUNG = 2 AND GETDATE() < CONVERT(DATETIME, BP_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM, 104) THEN 0 ELSE BP_STATUS_ZEITERFASSUNG END AS INT) ELSE CAST(CASE WHEN tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 2 AND GETDATE() < CONVERT(DATETIME, tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM, 104) THEN 0 ELSE tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG END AS INT) END AS STATUS_ZEITERFASSUNG, CAST(PSP_PREIS_HK_FK_EK_GP_IST AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_IST, CAST(PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST, CAST(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST, CAST(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST, CAST(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST, CAST(PSP_PREIS_VK_MINIMAL_IST AS FLOAT) AS PSP_PREIS_VK_MINIMAL_IST, CAST(PSP_PREIS_VK_IDEAL_IST AS FLOAT) AS PSP_PREIS_VK_IDEAL_IST, CAST(CASE WHEN PSP_TYP_HERKUNFT_IST_WERTE = 1 THEN  PSP_MENGE_IST  ELSE  CASE WHEN PSP_TYP_HERKUNFT_IST_WERTE = 0 THEN  ZE_BUCH_SUMME_MENGE_IST  ELSE  NULL  END  END AS FLOAT) AS PSP_MENGE_IST_WERT, CAST(tPPS_SKKALP.IDTR AS VARCHAR(30))AS IDTR, CAST(PSP_IDPSKKK_POS AS INT) AS PSP_IDPSKKK_POS, CAST(PSP_IDMS AS INT) AS PSP_IDMS, CAST(PSP_IDMP AS INT) AS PSP_IDMP, CAST(PSP_IDMR AS INT) AS PSP_IDMR, CAST(PSP_PP_ZEIT_MINUTEN_MAX_PROD_TAG AS FLOAT) AS PSP_PP_ZEIT_MINUTEN_MAX_PROD_TAG, CAST(PSP_TYP_HK_VK_PREIS_AKTUALISIERUNG AS SMALLINT) AS PSP_TYP_HK_VK_PREIS_AKTUALISIERUNG, CAST(PSP_TYP_ARBEITSSCHRITT_TEXT_AKTUALISIERUNG AS SMALLINT) AS PSP_TYP_ARBEITSSCHRITT_TEXT_AKTUALISIERUNG, CAST(PSP_TYP_EINSTELLUNG_BUCHUNG_AKTUALISIERUNG AS SMALLINT) AS PSP_TYP_EINSTELLUNG_BUCHUNG_AKTUALISIERUNG, CAST(PSP_TYP_LAYOUT_POSITION AS SMALLINT) AS PSP_TYP_LAYOUT_POSITION, CAST(PSP_ZEIT_TAGE_UEBERLAPPUNG AS FLOAT) AS PSP_ZEIT_TAGE_UEBERLAPPUNG, CAST(PSP_BUCHUNG_TYP_ZEIT AS SMALLINT) AS PSP_BUCHUNG_TYP_ZEIT, CAST(PSP_BUCHUNG_TYP_PRODUKTION AS SMALLINT) AS PSP_BUCHUNG_TYP_PRODUKTION, CAST(PSP_TYP_ERFASSUNG_ZEIT AS SMALLINT) AS PSP_TYP_ERFASSUNG_ZEIT, CAST(PSP_ZEIT_TAGE_PRODUKTION AS FLOAT) AS PSP_ZEIT_TAGE_PRODUKTION, CAST(PSP_MENGE_IST AS FLOAT) AS PSP_MENGE_IST, CAST(PSP_TYP_HERKUNFT_IST_WERTE AS SMALLINT) AS PSP_TYP_HERKUNFT_IST_WERTE, CAST(PSP_TYP_ERFASSUNG_IST_MENGE AS SMALLINT) AS PSP_TYP_ERFASSUNG_IST_MENGE, CAST(PSP_TYP_AKT_SOLL_MENGE AS SMALLINT) AS PSP_TYP_AKT_SOLL_MENGE, CAST(PSP_ZEIT_MINUTEN_PRODUKTION_AK_EINZEL_SOLL AS FLOAT) AS PSP_ZEIT_MINUTEN_PRODUKTION_AK_EINZEL_SOLL, CAST(PSP_ZEIT_MINUTEN_PRODUKTION_AK_GESAMT_SOLL AS FLOAT) AS PSP_ZEIT_MINUTEN_PRODUKTION_AK_GESAMT_SOLL, CAST(PSP_ZEIT_MINUTEN_PRODUKTION_MS_EINZEL_SOLL AS FLOAT) AS PSP_ZEIT_MINUTEN_PRODUKTION_MS_EINZEL_SOLL, CAST(PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL AS FLOAT) AS PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL, CAST(PSP_PREIS_VK_MINIMAL_RUESTUNG AS FLOAT) AS PSP_PREIS_VK_MINIMAL_RUESTUNG, CAST(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG AS MONEY) AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG, CAST(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG AS MONEY) AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, CAST(CASE WHEN PSP_TYP_KOSTENTYP = 1 THEN 0 ELSE CASE WHEN (ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG, 0) = 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP * PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL ELSE PSP_PREIS_HK_FK_EK_GP_RUESTUNG END  END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_RUESTUNG, CAST(PSP_PREIS_VK_MINIMAL_PRODUKTION AS FLOAT) AS PSP_PREIS_VK_MINIMAL_PRODUKTION, CAST(CASE WHEN PSP_TYP_KOSTENTYP = 1 THEN 0 ELSE CASE WHEN (ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) = 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP * PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL ELSE PSP_PREIS_HK_FK_EK_GP_PRODUKTION END  END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION, CAST(PSP_PREIS_VK_MINIMAL_PRODUKTION_AK AS FLOAT) AS PSP_PREIS_VK_MINIMAL_PRODUKTION_AK, CAST(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK AS MONEY) AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, CAST(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK AS MONEY) AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, CAST(CASE WHEN PSP_TYP_KOSTENTYP = 1 THEN 0 ELSE CASE WHEN (ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) = 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP * PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL ELSE PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK END  END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK, CAST(PSP_PREIS_VK_MINIMAL_PRODUKTION_MS AS FLOAT) AS PSP_PREIS_VK_MINIMAL_PRODUKTION_MS, CAST(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS AS MONEY) AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, CAST(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS AS MONEY) AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, CAST(CASE WHEN PSP_TYP_KOSTENTYP = 1 THEN 0 ELSE CASE WHEN (ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) = 0) THEN 0 ELSE PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS END  END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS, CAST(PSP_TYP_SPERRE AS SMALLINT) AS PSP_TYP_SPERRE ,CAST(ZE_BUCH_SUMME_ZEIT_RUESTUNG AS FLOAT) AS ZE_BUCH_SUMME_ZEIT_RUESTUNG ,CAST(ZE_BUCH_SUMME_ZEIT_PRODUKTION AS FLOAT) AS ZE_BUCH_SUMME_ZEIT_PRODUKTION ,CAST(ZE_BUCH_SUMME_MENGE_IST AS FLOAT) AS ZE_BUCH_SUMME_MENGE_IST ,CAST(ZE_BUCH_SUMME_MENGE_AUSSCHUSS AS FLOAT) AS ZE_BUCH_SUMME_MENGE_AUSSCHUSS ,CAST(ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK AS FLOAT) AS ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK ,CAST(ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS AS FLOAT) AS ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS , CAST(ZE_BUCH_SUMME_ZEIT_RUESTUNG + ZE_BUCH_SUMME_ZEIT_PRODUKTION AS FLOAT) AS PSP_ZEIT_MINUTEN_GESAMT_IST , CAST(ZE_BUCH_SUMME_ZEIT_RUESTUNG + ZE_BUCH_SUMME_ZEIT_PRODUKTION AS FLOAT) AS D4IV_PSP_ZEIT_MINUTEN_GESAMT_IST ,CAST(PSP_MENGE_IST_WERT_HK AS FLOAT) AS PSP_MENGE_IST_WERT_HK ,CAST(CASE WHEN ISNULL(PSP_PREIS_HK_FK_EK_GP,0) > ISNULL(PSP_PREIS_HK_FK_EK_GP_IST,0) THEN ISNULL(PSP_PREIS_HK_FK_EK_GP,0) - isnull(PSP_PREIS_HK_FK_EK_GP_IST,0) ELSE 0 END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_SOLL_OFFEN ,CAST(CASE WHEN ISNULL(PSP_PREIS_VK_MINIMAL,0) > ISNULL(PSP_PREIS_VK_MINIMAL_IST,0) THEN ISNULL(PSP_PREIS_VK_MINIMAL,0) - isnull(PSP_PREIS_VK_MINIMAL_IST,0) ELSE 0 END AS FLOAT) AS PSP_PREIS_VK_MINIMAL_SOLL_OFFEN ,CAST(CASE WHEN ISNULL(PSP_PREIS_VK_IDEAL,0) > ISNULL(PSP_PREIS_VK_IDEAL_IST,0) THEN ISNULL(PSP_PREIS_VK_IDEAL,0) - isnull(PSP_PREIS_VK_IDEAL_IST,0) ELSE 0 END AS FLOAT) AS PSP_PREIS_VK_IDEAL_SOLL_OFFEN ,CAST(CASE WHEN PSP_TYP_POSITION = 0 THEN CASE WHEN PSK_TYP_KALK_PREIS = 0 THEN  CASE WHEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG <> 0 OR PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK <> 0 OR PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS <> 0 THEN  1  ELSE 0  END  ELSE  CASE WHEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG <> 0 OR PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK <> 0 OR PS