ECKKOSTEN = 1 THEN PSP_ZEIT_MINUTEN_PRODUKTION_AK_EINZEL_SOLL ELSE CASE WHEN ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) = 0 THEN 0 ELSE PSP_ZEIT_MINUTEN_PRODUKTION_AK_GESAMT_SOLL / ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) END END END ELSE CASE WHEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK <> 0 OR PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS <> 0 THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS * CASE WHEN PSP_TYP_ERFASSUNG_ZEIT = 1 THEN CASE WHEN ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) = 0 THEN 0 ELSE (PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL  / CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END) END ELSE CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_ZEIT_MINUTEN_PRODUKTION_MS_EINZEL_SOLL ELSE CASE WHEN ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) = 0 THEN 0 ELSE PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL / ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) END END END + PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK * CASE WHEN PSP_TYP_ERFASSUNG_ZEIT = 1 THEN CASE WHEN ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) = 0 THEN 0 ELSE (PSP_ZEIT_MINUTEN_PRODUKTION_AK_GESAMT_SOLL  / CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END) END ELSE CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_ZEIT_MINUTEN_PRODUKTION_AK_EINZEL_SOLL ELSE CASE WHEN ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) = 0 THEN 0 ELSE PSP_ZEIT_MINUTEN_PRODUKTION_AK_GESAMT_SOLL / ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) END END END ELSE PSP_PREIS_HK_MIN_SATZ_FK_EK_EP * CASE WHEN PSP_TYP_ERFASSUNG_ZEIT = 1 THEN CASE WHEN ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) = 0 THEN 0 ELSE (PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL  / CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END) END ELSE CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL ELSE    CASE WHEN ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) = 0 THEN 0 ELSE PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL / ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) END END END END END ELSE 0 END AS PSP_PREIS_HK_FK_EK_EP_PRODUKTION_AK , CASE WHEN PSP_TYP_KOSTENTYP = 0 THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS * CASE WHEN PSP_TYP_ERFASSUNG_ZEIT = 1 THEN CASE WHEN ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) = 0 THEN 0 ELSE (PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL  / CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END) END ELSE CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_ZEIT_MINUTEN_PRODUKTION_MS_EINZEL_SOLL ELSE CASE WHEN ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) = 0 THEN 0 ELSE PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL / ISNULL(CASE WHEN PSP_TYP_BERECHNUNG_STUECKKOSTEN = 1 THEN PSP_MENGE_SOLL ELSE BP_MESU_FE_MENGE END, 0) END END END ELSE 0 END AS PSP_PREIS_HK_FK_EK_EP_PRODUKTION_MS , tBE_BELP.BP_IDAR AS BP_IDAR, tPPS_SKKALP.PSP_MENGE_IST_FAKTOR AS PSP_MENGE_IST_FAKTOR, 0 AS PSP_STATUS_MINDERMENGE_MATERIAL, tPRP.STATUS AS PRP_STATUS , tPRPK.ID_PRP AS ID_PRP , CAST(  CASE WHEN (CASE WHEN PSP_TYP_HERKUNFT_IST_WERTE = 1 THEN PSP_MENGE_IST ELSE CASE WHEN PSP_TYP_HERKUNFT_IST_WERTE = 0 THEN ZE_BUCH_SUMME_MENGE_IST ELSE 0 END END) = 0 THEN 0 ELSE (CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN ZE_BUCH_SUMME_ZEIT_PRODUKTION ELSE '' END + CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN ZE_BUCH_SUMME_ZEIT_RUESTUNG ELSE '' END) / CASE WHEN PSP_TYP_HERKUNFT_IST_WERTE = 1 THEN PSP_MENGE_IST ELSE CASE WHEN PSP_TYP_HERKUNFT_IST_WERTE = 0 THEN ZE_BUCH_SUMME_MENGE_IST ELSE 0 END END   END AS FLOAT) AS ZE_BUCH_SUMME_ZEIT_EINZEL , CAST(1 AS INT) AS PSP_TYP_ANZEIGE_BDE , CAST(0 AS INT) AS PSP_TYP_KOSTEN_KALKULATION , CAST(0 AS INT) AS PSP_TYP_IST_KOSTEN_ERMITTLUNG , CAST(CASE WHEN PSP_TYP_POSITION = 0 THEN ISNULL(tMARB_ZU_GRP.CNT_MARB_ZU, 0) ELSE -1 END AS INT) AS CNT_MARB_ZU , CAST(CASE WHEN PSP_TYP_POSITION = 0 THEN ISNULL(tMARB_ZU_GRP.MIN_MARB_ZU, '') ELSE '' END AS VARCHAR(100)) AS MIN_MARB_ZU , CAST(ROUND((CASE WHEN (CASE WHEN PSP_TYP_ERFASSUNG_ZEIT = 0 THEN (ROUND((CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL ELSE '' END * CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN PSP_MENGE_SOLL ELSE '' END), 0) + CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL ELSE '' END) ELSE CASE WHEN PSP_TYP_ERFASSUNG_ZEIT = 1 THEN CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL ELSE '' END + CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL ELSE '' END END END) = 0 THEN 0 ELSE CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN ZE_BUCH_SUMME_ZEIT_RUESTUNG + ZE_BUCH_SUMME_ZEIT_PRODUKTION  ELSE '' END /  CASE WHEN PSP_TYP_ERFASSUNG_ZEIT = 0 THEN (ROUND((CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL ELSE '' END * CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN PSP_MENGE_SOLL ELSE '' END), 0) + CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL ELSE '' END) ELSE CASE WHEN PSP_TYP_ERFASSUNG_ZEIT = 1 THEN CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL ELSE '' END + CASE WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL ELSE '' END END END END) * 100, 0) AS INT) AS PSP_FORTSCHRITT_PROZENT , CAST(tPPS_ARBSCHR.AS_TYP_FARBE_ARBEITSSCHRITT AS INT) AS AS_TYP_FARBE_ARBEITSSCHRITT , CASE WHEN EXISTS(SELECT tZE_BUCH_BEWE.ID FROM tZE_BUCH INNER JOIN tZE_BUCH_BEWE ON tZE_BUCH_BEWE.ZBUBW_IDZBU = tZE_BUCH.ID WHERE tZE_BUCH.ZBU_IDPSKP = tPPS_SKKALP.ID AND ISNULL(tZE_BUCH_BEWE.ZBUBW_DATUM_ZEIT_START, '') <> '' AND ISNULL(tZE_BUCH_BEWE.ZBUBW_DATUM_ZEIT_STOP , '') = '') THEN 1 ELSE 0 END AS PSP_AKTIV , CAST(PSP_PP_NLZ_PROZENT AS FLOAT) AS PSP_PP_NLZ_PROZENT, CAST(PSP_TYP_BERECHNUNG_STUECKKOSTEN AS INT) AS PSP_TYP_BERECHNUNG_STUECKKOSTEN, CAST(0 AS FLOAT) AS KP_GEWICHT_KG_NETTO , CAST(0 AS FLOAT) AS KP_GEWICHT_KG_BRUTTO , CAST(0 AS FLOAT) AS KP_GEWICHT_KG_NETTO_GES , CAST(0 AS FLOAT) AS KP_GEWICHT_KG_BRUTTO_GES  FROM (((((((((((((((((((SELECT tPPS_SKKALP.*,  PSP_MENGE_IST_WERT_HK, PSP_PREIS_VK_IDEAL_IST, PSP_PREIS_VK_MINIMAL_IST, PSP_PREIS_HK_FK_EK_GP_IST, PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST, PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST, PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST, PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST, ZE_BUCH_SUMME_MENGE_AUSSCHUSS, ZE_BUCH_SUMME_MENGE_IST, ZE_BUCH_SUMME_ZEIT_RUESTUNG, ZE_BUCH_SUMME_ZEIT_PRODUKTION, ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK, ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS FROM tPPS_SKKALP LEFT JOIN ( SELECT ID AS IDPSP_TEMP, SUM(ISNULL(PSP_MENGE_IST_WERT_HK, 0)) AS PSP_MENGE_IST_WERT_HK, SUM(ISNULL(PSP_PREIS_VK_IDEAL_IST, 0)) AS PSP_PREIS_VK_IDEAL_IST, SUM(ISNULL(PSP_PREIS_VK_MINIMAL_IST, 0)) AS PSP_PREIS_VK_MINIMAL_IST, SUM(ISNULL(PSP_PREIS_HK_FK_EK_GP_IST, 0)) AS PSP_PREIS_HK_FK_EK_GP_IST, SUM(ISNULL(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST, 0)) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST, SUM(ISNULL(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST, 0)) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST, SUM(ISNULL(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST, 0)) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST, SUM(ISNULL(PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST, 0)) AS PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST, SUM(ISNULL(ZE_BUCH_SUMME_MENGE_AUSSCHUSS, 0)) AS ZE_BUCH_SUMME_MENGE_AUSSCHUSS, SUM(ISNULL(ZE_BUCH_SUMME_MENGE_IST, 0)) AS ZE_BUCH_SUMME_MENGE_IST, SUM(ISNULL(ZE_BUCH_SUMME_ZEIT_RUESTUNG, 0)) AS ZE_BUCH_SUMME_ZEIT_RUESTUNG, SUM(ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION, 0)) AS ZE_BUCH_SUMME_ZEIT_PRODUKTION, SUM(ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK, 0)) AS ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK, SUM(ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS, 0)) AS ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS FROM (SELECT * , CASE WHEN PSP_TYP_HERKUNFT_IST_WERTE = 1 THEN  PSP_MENGE_IST  ELSE  CASE WHEN PSP_TYP_HERKUNFT_IST_WERTE = 0 THEN  ZE_BUCH_SUMME_MENGE_IST  ELSE  NULL  END  END AS PSP_MENGE_IST_WERT_HK FROM (SELECT *, 'PSP_PREIS_VK_IDEAL_IST' = CASE WHEN PSP_TYP_POSITION = 0 THEN CASE WHEN ISNULL(PSP_PREIS_VK_IDEAL,0) > 0 AND ISNULL(PSP_PREIS_HK_FK_EK_GP,0) > 0 THEN CASE WHEN ISNULL(PSP_PREIS_HK_FK_EK_GP,0) <> ISNULL(PSP_PREIS_VK_IDEAL,0) THEN PSP_PREIS_HK_FK_EK_GP_IST + ((PSP_PREIS_HK_FK_EK_GP_IST * ((PSP_PREIS_VK_IDEAL - PSP_PREIS_HK_FK_EK_GP) * 100 / PSP_PREIS_HK_FK_EK_GP)) / 100) ELSE PSP_PREIS_HK_FK_EK_GP_IST END ELSE CASE WHEN PSK_TYP_KALK_PREIS_TYP = 0 THEN ISNULL(PSP_PREIS_HK_FK_EK_GP_IST,0) ELSE CASE WHEN PSP_TYP_POSITION = 0 THEN CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) <> 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG ELSE CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_RUESTUNG,0) + CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) <> 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK ELSE CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,0) + CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) <> 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS ELSE CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,0) ELSE ISNULL(PSP_PREIS_VK_MINIMAL,0) END END END ELSE ISNULL(PSP_PREIS_VK_IDEAL,0) END, 'PSP_PREIS_VK_MINIMAL_IST' = CASE WHEN PSK_TYP_KALK_PREIS_TYP = 0 THEN ISNULL(PSP_PREIS_HK_FK_EK_GP_IST,0) ELSE CASE WHEN PSP_TYP_POSITION = 0 THEN CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) <> 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG ELSE CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_RUESTUNG,0) + CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) <> 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK ELSE CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,0) + CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) <> 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS ELSE CASE WHEN ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0 THEN PSP_PREIS_VK_MIN_SATZ_FK_VK_EP ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,0) ELSE ISNULL(PSP_PREIS_VK_MINIMAL,0) END END FROM (SELECT *, 'PSP_PREIS_HK_FK_EK_GP_IST' = CASE WHEN PSP_TYP_POSITION = 0 THEN CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG, 0) <> 0) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) <> 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG ELSE CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND (ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) = 0) ) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND (ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0) ) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_RUESTUNG,0) + CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) <> 0) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) <> 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK ELSE CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND (ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) = 0) ) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND (ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0) ) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,0) + CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) <> 0) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) <> 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS ELSE CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND (ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) = 0) ) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND (ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0) ) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,0) ELSE ISNULL(PSP_PREIS_HK_FK_EK_GP,0) END , 'PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST' = CASE WHEN PSP_TYP_POSITION = 0 THEN CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) <> 0) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) <> 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK ELSE CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND (ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) = 0) ) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND (ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0) ) THEN ( PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK + PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS )ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,0) + CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) <> 0) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) <> 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS ELSE CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND (ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) = 0) ) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND (ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0) ) THEN ( PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK + PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS )ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,0) ELSE ISNULL(PSP_PREIS_HK_FK_EK_GP_PRODUKTION,0) END , 'PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST' = CASE WHEN PSP_TYP_POSITION = 0 THEN CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) <> 0) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) <> 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK ELSE CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, 0) = 0 ) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, 0) = 0  ) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,0) ELSE ISNULL(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK,0) END , 'PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST' = CASE WHEN PSP_TYP_POSITION = 0 THEN CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) <> 0) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) <> 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS ELSE CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, 0) = 0 ) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, 0) = 0  ) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,0) ELSE ISNULL(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS,0) END , 'PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST' = CASE WHEN PSP_TYP_POSITION = 0 THEN CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG, 0) <> 0) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) <> 0) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG ELSE CASE WHEN (PSK_TYP_KALK_PREIS_TYP = 0 AND ISNULL(PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG, 0) = 0 ) OR (PSK_TYP_KALK_PREIS_TYP = 1 AND ISNULL(PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, 0) = 0  ) THEN PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG ELSE 0 END END * ISNULL(ZE_BUCH_SUMME_ZEIT_RUESTUNG,0) ELSE ISNULL(PSP_PREIS_HK_FK_EK_GP_RUESTUNG,0) END FROM ( SELECT tPPS_SKKALP.ID, PSP_IDPSKKK, PSP_TYP_POSITION, CASE WHEN ISNULL(ZBU_IDMS, 0) <> 0 AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0) AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN MS_KOSTEN_R ELSE PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG END AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG, CASE WHEN ISNULL(ZBU_IDMS, 0) <> 0 AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0) AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN MS_PREIS_R ELSE PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG END AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG, CASE WHEN ISNULL(ZBU_IDMS, 0) <> 0 AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0) AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN MS_KOSTEN_PA ELSE PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK END AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK, CASE WHEN ISNULL(ZBU_IDMS, 0) <> 0 AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0) AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN MS_PREIS_PA ELSE PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK END AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK, CASE WHEN ISNULL(ZBU_IDMS, 0) <> 0 AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0) AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN MS_KOSTEN_PM ELSE PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS END AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS, CASE WHEN ISNULL(ZBU_IDMS, 0) <> 0 AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0) AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN MS_PREIS_PM ELSE PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS END AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS, CASE WHEN ISNULL(ZBU_IDMS, 0) <> 0 AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0) AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN MS_KOSTEN ELSE PSP_PREIS_HK_MIN_SATZ_FK_EK_EP END AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP, CASE WHEN ISNULL(ZBU_IDMS, 0) <> 0 AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0) AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN MS_PREIS ELSE PSP_PREIS_VK_MIN_SATZ_FK_VK_EP END AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP, PSP_PREIS_HK_FK_EK_GP, PSP_PREIS_HK_FK_EK_GP_PRODUKTION, PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK, PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS, PSP_PREIS_HK_FK_EK_GP_RUESTUNG, PSP_PREIS_VK_IDEAL, PSP_PREIS_VK_MINIMAL, PSP_TYP_HERKUNFT_IST_WERTE, PSP_MENGE_IST, PSK_TYP_KALK_PREIS_TYP, ZE_BUCH_SUMME_MENGE_AUSSCHUSS, ZE_BUCH_SUMME_MENGE_IST, ZE_BUCH_SUMME_ZEIT_RUESTUNG, ZE_BUCH_SUMME_ZEIT_PRODUKTION, ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK, ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS FROM (tPPS_SKKALP LEFT JOIN (SELECT PSK_TYP_KALK_PREIS AS PSK_TYP_KALK_PREIS_TYP, ID AS PSK_TYP_KALK_PREIS_ID FROM tPPS_SKKALK ) AS tPPS_SKKALK_TYP_KALK_PREIS ON tPPS_SKKALK_TYP_KALK_PREIS.PSK_TYP_KALK_PREIS_ID = tPPS_SKKALP.PSP_IDPSKKK)  left join ( select      tZE_BUCH.ZBU_IDPSKP,             tZE_BUCH.ZBU_IDMS,         ZBU_MENGE_AUSSCHUSS AS ZE_BUCH_SUMME_MENGE_AUSSCHUSS,         ZBU_MENGE_IST AS ZE_BUCH_SUMME_MENGE_IST,         case when tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT = 0 then isnull(ZBUBW_ZEIT,0) else 0 end as ZE_BUCH_SUMME_ZEIT_RUESTUNG,         case when tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT = 1 then isnull(ZBUBW_ZEIT,0) else 0 end as ZE_BUCH_SUMME_ZEIT_PRODUKTION,         case when tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT = 1 then case when tZE_BUCH_BEWE.ZBUBW_TYP_PRODUKTION = 0 then isnull(ZBUBW_ZEIT,0) else 0 end else 0 end as ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,         case when tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT = 1 then case when tZE_BUCH_BEWE.ZBUBW_TYP_PRODUKTION = 1 then isnull(ZBUBW_ZEIT,0) else 0 end else 0 end as ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS from tZE_BUCH left join   tPPS_SKKALP     on      tPPS_SKKALP.ID = tZE_BUCH.ZBU_IDPSKP left join (     select             case when isnull(ZBUBW_DATUM_ZEIT_START, 0) <> 0 and isnull(ZBUBW_DATUM_ZEIT_STOP, 0) <> 0 then                 ROUND(CAST(datediff(ss, ZBUBW_DATUM_ZEIT_START, ZBUBW_DATUM_ZEIT_STOP) AS FLOAT) / 60, 4)             else                 case when isnull(ZBUBW_DATUM_ZEIT_START,0) <> 0 and isnull(ZBUBW_DATUM_ZEIT_STOP,0) = 0 then                     ROUND(CAST(datediff(ss, ZBUBW_DATUM_ZEIT_START, getdate()) AS FLOAT) / 60, 4)                 else                     0                 end             end as ZBUBW_ZEIT,                 tZE_BUCH_BEWE.ZBUBW_IDZBU,                 tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT,                 tZE_BUCH_BEWE.ZBUBW_TYP_PRODUKTION,                 tZE_BUCH_BEWE.ZBUBW_DATUM_ZEIT_STOP     from tZE_BUCH_BEWE ) as tZE_BUCH_BEWE   on tZE_BUCH_BEWE.ZBUBW_IDZBU = tZE_BUCH.ID ) AS tZE_BUCH   ON tZE_BUCH.ZBU_IDPSKP = tPPS_SKKALP.ID  LEFT JOIN tPPS_MASTA ON tPPS_MASTA.ID = tZE_BUCH.ZBU_IDMS ) AS MATRIX3 ) AS MATRIX2 ) AS MATRIX3 ) AS TEMP GROUP BY ID )AS tPPS_SKKALP_TEMP ON tPPS_SKKALP_TEMP.IDPSP_TEMP = tPPS_SKKALP.ID ) AS tPPS_SKKALP LEFT JOIN tPPS_ARBSCHR ON tPPS_ARBSCHR.ID = tPPS_SKKALP.PSP_IDAS) LEFT JOIN tPPS_MASTA ON tPPS_MASTA.ID = tPPS_SKKALP.PSP_IDMS) LEFT JOIN tPPS_MASCHPOOL ON tPPS_MASCHPOOL.ID = tPPS_SKKALP.PSP_IDMP) LEFT JOIN tMARB ON tMARB.ID = tPPS_SKKALP.PSP_IDMR) LEFT JOIN tADRS ON tADRS.ID = tMARB.MA_IDAD) LEFT JOIN (   SELECT        MIN(tPPS_SKKALP_ZU.ID) AS IDZU_MIN,        COUNT(tPPS_SKKALP_ZU.PSZ_IDPSP) AS IDZU_ANZAHL,        tPPS_SKKALP_ZU.PSZ_IDPSP    FROM        tPPS_SKKALP_ZU    GROUP BY tPPS_SKKALP_ZU.PSZ_IDPSP ) As tPPS_SKKALP_ZU2 ON tPPS_SKKALP_ZU2.PSZ_IDPSP = tPPS_SKKALP.ID) LEFT JOIN tPPS_SKKALP_ZU AS tPPS_SKKALP_ZU3 ON tPPS_SKKALP_ZU3.ID = tPPS_SKKALP_ZU2.IDZU_MIN) LEFT JOIN (   SELECT        tPPS_SKKALP.ID AS PSP_IDZU,        tPPS_SKKALP.PSP_IDAS AS IDAS_ZU,        PSP_POSITION_NUMMER AS PSP_POSITION_NUMMER_ZU    FROM        tPPS_SKKALP ) AS tPPS_SKKALP2 ON tPPS_SKKALP2.PSP_IDZU = tPPS_SKKALP_ZU3.PSZ_IDPSP_ZU) LEFT JOIN (   SELECT        tPPS_ARBSCHR.ID,        tPPS_ARBSCHR.AS_NUMMER AS PSP_ARBEITSSCHRITT_NUMMER_ZU    FROM        tPPS_ARBSCHR ) AS tPPS_ARBSCHR_ZU ON tPPS_ARBSCHR_ZU.ID = tPPS_SKKALP2.IDAS_ZU) LEFT JOIN tPPS_SKKALK ON tPPS_SKKALK.ID = tPPS_SKKALP.PSP_IDPSKKK) LEFT JOIN tPPS_SKKALV ON tPPS_SKKALV.ID = tPPS_SKKALK.PSK_IDPSKKV) LEFT JOIN tBE_BELP ON tBE_BELP.ID = tPPS_SKKALK.PSK_IDBEBP) LEFT JOIN tBE_BELP_MESU ON tBE_BELP_MESU.BP_MESU_IDBEBP = tBE_BELP.ID)  LEFT JOIN (      SELECT  BK_BKBE_IDBEBK,          BK_BKBE_STATUS_ZEITERFASSUNG,          BK_BKBE_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM      FROM    tBE_BELK_BKBE  ) AS tBE_BELK_BKBE_OFFEN  ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK OR tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tPPS_SKKALK.PSK_IDBEBK)  LEFT JOIN ( SELECT CASE WHEN COUNT_NOT_OK > 0 THEN  2 ELSE 1 END AS [STATUS], PREK_IDPSP FROM ( SELECT PREK_IDPSP, SUM(ISNULL(COUNT_OK, 0)) AS COUNT_OK, SUM(ISNULL(COUNT_NOT_OK, 0)) AS COUNT_NOT_OK FROM ( SELECT PREK_IDPSP, (SELECT COUNT(ID) FROM tPRP_ERGBP WHERE (PREP_FELD_VALID <> 0 OR (PREP_FELD_VALID <> 0 AND CAST(PREP_FELD_VALID_FORMEL AS VARCHAR(2000)) = '')) AND PREP_IDPREK = tPRP_ERGBK.ID) AS COUNT_OK, (SELECT COUNT(ID) FROM tPRP_ERGBP WHERE PREP_FELD_VALID = 0 AND CAST(PREP_FELD_VALID_FORMEL AS VARCHAR(2000)) <> '' AND PREP_IDPREK = tPRP_ERGBK.ID) AS COUNT_NOT_OK FROM tPRP_ERGBK WHERE PREK_PRPK_TYP = 0 ) AS TEMP GROUP BY PREK_IDPSP ) AS TEMP ) AS tPRP ON tPRP.PREK_IDPSP = tPPS_SKKALP.ID) LEFT JOIN ( SELECT PSMZ_IDPSKP, CNT_MARB_ZU, AD_NAME1 + CASE WHEN CNT_MARB_ZU > 1 THEN ' (...)' ELSE '' END AS MIN_MARB_ZU FROM ( SELECT COUNT(ID) AS CNT_MARB_ZU, MIN(PSMZ_IDMR) AS MIN_IDMR, PSMZ_IDPSKP FROM tPPS_SKKALP_MARB_ZU GROUP BY PSMZ_IDPSKP ) AS GRP_MARB_ZU LEFT JOIN (SELECT ID, MA_IDAD FROM tMARB) AS tMARB ON tMARB.ID = GRP_MARB_ZU.MIN_IDMR LEFT JOIN (SELECT ID, AD_NAME1 FROM tADRS) AS tADRS ON tADRS.ID = tMARB.MA_IDAD ) AS tMARB_ZU_GRP ON tMARB_ZU_GRP.PSMZ_IDPSKP = tPPS_SKKALP.ID)  LEFT JOIN ( SELECT ID_PSP, CASE WHEN CNT_PRP > 1 THEN '...' ELSE SUBSTRING(PRV_NUMMER, 1, 5) END AS PRP_AW, CASE WHEN CNT_PRP > 0 THEN 1 ELSE 0 END AS PRP_AW_INDIKATOR  FROM ( SELECT ID_PSP, MAX(ID_PRP) AS ID_PRP, MAX(CNT_PRP) AS CNT_PRP FROM ( SELECT ID_PSP, MAX(ID_PRP) AS ID_PRP, COUNT(ID_PRP) AS CNT_PRP FROM ( SELECT tPPS_SKKALP.ID AS ID_PSP, CASE WHEN ISNULL(tPRP_PLANK.ID, 0) <> 0 THEN ISNULL(tPRP_PLANK.ID, 0) WHEN ISNULL(tPRP_PLANK_V.ID, 0) <> 0 THEN ISNULL(tPRP_PLANK_V.ID, 0) WHEN ISNULL(tPRP_PLANK_V_ARST.ID, 0) <> 0 THEN ISNULL(tPRP_PLANK_V_ARST.ID, 0) WHEN ISNULL(tPRP_PLANK_V_ARGR.ID, 0) <> 0 THEN ISNULL(tPRP_PLANK_V_ARGR.ID, 0) ELSE 0 END AS ID_PRP FROM (SELECT * FROM tPPS_SKKALP ) tPPS_SKKALP LEFT JOIN tPPS_SKKALK ON tPPS_SKKALK.ID = tPPS_SKKALP.PSP_IDPSKKK LEFT JOIN (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 1) AS tPRP_PLANK ON tPRP_PLANK.PRK_IDPSP = tPPS_SKKALP.ID LEFT JOIN (SELECT * FROM tPRP_PRVZU WHERE PRVZ_TYP_PRUEFUNG = 4 AND CASE WHEN PRVZ_DATUM_BIS IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN 1 ELSE 0 END END = 1 AND CASE WHEN PRVZ_DATUM_VON IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN 1 ELSE 0 END END = 1 AND ((ISNULL(PRVZ_IDMR, 0) = 0 AND ISNULL(PRVZ_IDMG, 0) = 0) OR ISNULL(PRVZ_IDMR, 0) IN (SELECT ID FROM tMARB WHERE MA_IDBE = 0) OR  ISNULL(PRVZ_IDMG, 0) IN (SELECT ID FROM tMGMI WHERE MM_IDMR = (SELECT ID FROM tMARB WHERE MA_IDBE = 0)))) AS tPRP_PRVZU ON tPRP_PRVZU.PRVZ_IDPSP = tPPS_SKKALP.ID LEFT JOIN tPRP_PLANV ON tPRP_PLANV.ID = tPRP_PRVZU.PRVZ_IDPRPPV LEFT JOIN (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 1) AS tPRP_PLANK_V ON tPRP_PLANK_V.PRK_IDPRPPV = tPRP_PLANV.ID LEFT JOIN tBE_BELP ON tBE_BELP.ID = tPPS_SKKALK.PSK_IDBEBP LEFT JOIN (SELECT * FROM tPRP_PRVZU WHERE PRVZ_TYP_PRUEFUNG = 4 AND CASE WHEN PRVZ_DATUM_BIS IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN 1 ELSE 0 END END = 1 AND CASE WHEN PRVZ_DATUM_VON IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN 1 ELSE 0 END END = 1 AND ((ISNULL(PRVZ_IDMR, 0) = 0 AND ISNULL(PRVZ_IDMG, 0) = 0) OR ISNULL(PRVZ_IDMR, 0)IN (SELECT ID FROM tMARB WHERE MA_IDBE = 0) OR  ISNULL(PRVZ_IDMG, 0) IN (SELECT ID FROM tMGMI WHERE MM_IDMR = (SELECT ID FROM tMARB WHERE MA_IDBE = 0)))) AS tPRP_PRVZU_ARST ON tPRP_PRVZU_ARST.PRVZ_IDAR = tBE_BELP.BP_IDAR LEFT JOIN tPRP_PLANV AS tPRP_PLANV_ARST ON tPRP_PLANV_ARST.ID = tPRP_PRVZU_ARST.PRVZ_IDPRPPV LEFT JOIN (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 1) AS tPRP_PLANK_V_ARST ON tPRP_PLANK_V_ARST.PRK_IDPRPPV = tPRP_PLANV_ARST.ID LEFT JOIN (SELECT * FROM tPRP_PRVZU WHERE PRVZ_TYP_PRUEFUNG = 4 AND CASE WHEN PRVZ_DATUM_BIS IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN 1 ELSE 0 END END = 1 AND CASE WHEN PRVZ_DATUM_VON IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN 1 ELSE 0 END END = 1 AND ((ISNULL(PRVZ_IDMR, 0) = 0 AND ISNULL(PRVZ_IDMG, 0) = 0) OR ISNULL(PRVZ_IDMR, 0) IN (SELECT ID FROM tMARB WHERE MA_IDBE = 0) OR  ISNULL(PRVZ_IDMG, 0) IN (SELECT ID FROM tMGMI WHERE MM_IDMR = (SELECT ID FROM tMARB WHERE MA_IDBE = 0)))) AS tPRP_PRVZU_ARGR ON tPRP_PRVZU_ARGR.PRVZ_IDAG IN (SELECT AM_IDAG FROM tAGMI WHERE AM_IDAR = tBE_BELP.BP_IDAR AND CASE WHEN AM_DATUM_BIS IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) <= AM_DATUM_BIS THEN 1 ELSE 0 END END = 1 AND CASE WHEN AM_DATUM_VON IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) >= AM_DATUM_VON THEN 1 ELSE 0 END END = 1) LEFT JOIN tPRP_PLANV AS tPRP_PLANV_ARGR ON tPRP_PLANV_ARGR.ID = tPRP_PRVZU_ARGR.PRVZ_IDPRPPV LEFT JOIN (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 1) AS tPRP_PLANK_V_ARGR ON tPRP_PLANK_V_ARGR.PRK_IDPRPPV = tPRP_PRVZU_ARGR.ID ) AS tPRPK_TEMP WHERE tPRPK_TEMP.ID_PRP != 0 GROUP BY ID_PSP) AS TEMP GROUP BY ID_PSP ) AS T  LEFT JOIN (SELECT * FROM tPRP_PLANK) AS tPRP_PLANK ON tPRP_PLANK.ID = ID_PRP  LEFT JOIN (SELECT * FROM tPRP_PLANV) AS tPRP_PLANV ON tPRP_PLANV.ID = tPRP_PLANK.PRK_IDPRPPV ) AS tPRP_AW ON tPRP_AW.ID_PSP = tPPS_SKKALP.ID ) LEFT JOIN ( SELECT ID_PSP, MAX(ID_PRP) AS ID_PRP FROM ( SELECT ID_PSP, MAX(ID_PRP) AS ID_PRP FROM ( SELECT tPPS_SKKALP.ID AS ID_PSP, CASE WHEN ISNULL(tPRP_PLANK.ID, 0) <> 0 THEN ISNULL(tPRP_PLANK.ID, 0) WHEN ISNULL(tPRP_PLANK_V.ID, 0) <> 0 THEN ISNULL(tPRP_PLANK_V.ID, 0) WHEN ISNULL(tPRP_PLANK_V_ARST.ID, 0) <> 0 THEN ISNULL(tPRP_PLANK_V_ARST.ID, 0) WHEN ISNULL(tPRP_PLANK_V_ARGR.ID, 0) <> 0 THEN ISNULL(tPRP_PLANK_V_ARGR.ID, 0) ELSE 0 END AS ID_PRP FROM (SELECT * FROM tPPS_SKKALP ) tPPS_SKKALP LEFT JOIN tPPS_SKKALK ON tPPS_SKKALK.ID = tPPS_SKKALP.PSP_IDPSKKK LEFT JOIN (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 0) AS tPRP_PLANK ON tPRP_PLANK.PRK_IDPSP = tPPS_SKKALP.ID LEFT JOIN (SELECT * FROM tPRP_PRVZU WHERE PRVZ_TYP_PRUEFUNG = 4 AND CASE WHEN PRVZ_DATUM_BIS IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN 1 ELSE 0 END END = 1 AND CASE WHEN PRVZ_DATUM_VON IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN 1 ELSE 0 END END = 1 AND ((ISNULL(PRVZ_IDMR, 0) = 0 AND ISNULL(PRVZ_IDMG, 0) = 0) OR ISNULL(PRVZ_IDMR, 0) IN (SELECT ID FROM tMARB WHERE MA_IDBE = 0) OR  ISNULL(PRVZ_IDMG, 0) IN (SELECT ID FROM tMGMI WHERE MM_IDMR = (SELECT ID FROM tMARB WHERE MA_IDBE = 0)))) AS tPRP_PRVZU ON tPRP_PRVZU.PRVZ_IDPSP = tPPS_SKKALP.ID LEFT JOIN tPRP_PLANV ON tPRP_PLANV.ID = tPRP_PRVZU.PRVZ_IDPRPPV LEFT JOIN (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 0) AS tPRP_PLANK_V ON tPRP_PLANK_V.PRK_IDPRPPV = tPRP_PLANV.ID LEFT JOIN tBE_BELP ON tBE_BELP.ID = tPPS_SKKALK.PSK_IDBEBP LEFT JOIN (SELECT * FROM tPRP_PRVZU WHERE PRVZ_TYP_PRUEFUNG = 4 AND CASE WHEN PRVZ_DATUM_BIS IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN 1 ELSE 0 END END = 1 AND CASE WHEN PRVZ_DATUM_VON IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN 1 ELSE 0 END END = 1 AND ((ISNULL(PRVZ_IDMR, 0) = 0 AND ISNULL(PRVZ_IDMG, 0) = 0) OR ISNULL(PRVZ_IDMR, 0)IN (SELECT ID FROM tMARB WHERE MA_IDBE = 0) OR  ISNULL(PRVZ_IDMG, 0) IN (SELECT ID FROM tMGMI WHERE MM_IDMR = (SELECT ID FROM tMARB WHERE MA_IDBE = 0)))) AS tPRP_PRVZU_ARST ON tPRP_PRVZU_ARST.PRVZ_IDAR = tBE_BELP.BP_IDAR LEFT JOIN tPRP_PLANV AS tPRP_PLANV_ARST ON tPRP_PLANV_ARST.ID = tPRP_PRVZU_ARST.PRVZ_IDPRPPV LEFT JOIN (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 0) AS tPRP_PLANK_V_ARST ON tPRP_PLANK_V_ARST.PRK_IDPRPPV = tPRP_PLANV_ARST.ID LEFT JOIN (SELECT * FROM tPRP_PRVZU WHERE PRVZ_TYP_PRUEFUNG = 4 AND CASE WHEN PRVZ_DATUM_BIS IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN 1 ELSE 0 END END = 1 AND CASE WHEN PRVZ_DATUM_VON IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN 1 ELSE 0 END END = 1 AND ((ISNULL(PRVZ_IDMR, 0) = 0 AND ISNULL(PRVZ_IDMG, 0) = 0) OR ISNULL(PRVZ_IDMR, 0) IN (SELECT ID FROM tMARB WHERE MA_IDBE = 0) OR  ISNULL(PRVZ_IDMG, 0) IN (SELECT ID FROM tMGMI WHERE MM_IDMR = (SELECT ID FROM tMARB WHERE MA_IDBE = 0)))) AS tPRP_PRVZU_ARGR ON tPRP_PRVZU_ARGR.PRVZ_IDAG IN (SELECT AM_IDAG FROM tAGMI WHERE AM_IDAR = tBE_BELP.BP_IDAR AND CASE WHEN AM_DATUM_BIS IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) <= AM_DATUM_BIS THEN 1 ELSE 0 END END = 1 AND CASE WHEN AM_DATUM_VON IS NULL THEN 1 ELSE CASE WHEN CONVERT(DATETIME, GETDATE(), 104) >= AM_DATUM_VON THEN 1 ELSE 0 END END = 1) LEFT JOIN tPRP_PLANV AS tPRP_PLANV_ARGR ON tPRP_PLANV_ARGR.ID = tPRP_PRVZU_ARGR.PRVZ_IDPRPPV LEFT JOIN (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 0) AS tPRP_PLANK_V_ARGR ON tPRP_PLANK_V_ARGR.PRK_IDPRPPV = tPRP_PRVZU_ARGR.ID ) AS tPRPK_TEMP WHERE tPRPK_TEMP.ID_PRP != 0 GROUP BY ID_PSP) AS TEMP GROUP BY ID_PSP ) AS tPRPK ON tPRPK.ID_PSP = tPPS_SKKALP.ID )) AS tPPS_SKKALP  WHERE ID = 6313
